      "example": "//@version=6strategy(\"`session.islastbar_regular` Example\", overlay = true)longCondition = year >= 2022// Place a long order at the `close` of the trading session's first bar.if session.isfirstbar and longCondition    strategy.entry(\"Long\", strategy.long)// Close the long position at the `close` of the trading session's last bar.if session.islastbar_regular and barstate.isconfirmed    strategy.close(\"Long\", immediately = true)",
